import{_ as o,C as t,o as a,c as u,a5 as p,b as e,w as n,a as i,E as r,a4 as c}from"./chunks/framework.gGRxziV4.js";const C=JSON.parse('{"title":"07 - Rules 系统：给 AI 立\\"家规\\"","description":"","frontmatter":{},"headers":[],"relativePath":"08-ECC教程/07-Rules系统.md","filePath":"08-ECC教程/07-Rules系统.md","lastUpdated":null}'),b={name:"08-ECC教程/07-Rules系统.md"};function m(d,s,E,h,A,g){const l=t("Mermaid");return a(),u("div",null,[s[2]||(s[2]=p(`<h1 id="_07-rules-系统-给-ai-立-家规" tabindex="-1">07 - Rules 系统：给 AI 立&quot;家规&quot; <a class="header-anchor" href="#_07-rules-系统-给-ai-立-家规" aria-label="Permalink to &quot;07 - Rules 系统：给 AI 立&quot;家规&quot;&quot;">​</a></h1><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to &quot;一句话总结&quot;">​</a></h2><p>没有 Rules 的 AI 写代码就像&quot;没有风格指南的自由撰稿人&quot;——能写，但写出来的东西风格不统一，质量参差不齐。Rules 就是给 AI 立规矩，确保 TA 在任何项目里都按统一标准行事。</p><hr><h2 id="真实痛点-ai-的代码-风格混乱" tabindex="-1">真实痛点：AI 的代码&quot;风格混乱&quot; <a class="header-anchor" href="#真实痛点-ai-的代码-风格混乱" aria-label="Permalink to &quot;真实痛点：AI 的代码&quot;风格混乱&quot;&quot;">​</a></h2><p>想象你是一个团队负责人。你们团队有 5 个人，每人都在用 AI 写代码。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>开发者 A 的 AI 输出：</span></span>
<span class="line"><span>  - tab 缩进</span></span>
<span class="line"><span>  - 英文注释</span></span>
<span class="line"><span>  - 没有测试</span></span>
<span class="line"><span>  - 函数写了 200 行</span></span>
<span class="line"><span></span></span>
<span class="line"><span>开发者 B 的 AI 输出：</span></span>
<span class="line"><span>  - 空格缩进（4 空格）</span></span>
<span class="line"><span>  - 中文注释</span></span>
<span class="line"><span>  - 有测试但覆盖率很低</span></span>
<span class="line"><span>  - 函数 30 行</span></span>
<span class="line"><span></span></span>
<span class="line"><span>开发者 C 的 AI 输出：</span></span>
<span class="line"><span>  - 空格缩进（2 空格）</span></span>
<span class="line"><span>  - 没有注释</span></span>
<span class="line"><span>  - 偶尔写测试</span></span>
<span class="line"><span>  - 文件有 1000 行</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br></div></div><p>代码审查的时候你会崩溃——每个人（的 AI）都在用不同的风格。<strong>代码能跑，但不可维护。</strong></p><p>为什么会这样？因为 AI 没有&quot;团队标准&quot;。TA 知道怎么写代码，但不知道&quot;在我们团队，代码应该这样写&quot;。</p><p><strong>Rules 就是解决这个问题的——一套明确的&quot;法律&quot;，所有 AI 输出都必须遵守。</strong></p><hr><h2 id="rules-的核心设计-分层" tabindex="-1">Rules 的核心设计：分层 <a class="header-anchor" href="#rules-的核心设计-分层" aria-label="Permalink to &quot;Rules 的核心设计：分层&quot;">​</a></h2><p>Rules 不是一锅端的，而是分层设计的。为什么？因为有些规矩是通用的，有些是语言特有的。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Rules = 公司员工手册（两层）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌────────────────────────────────────────┐</span></span>
<span class="line"><span>│  第一层：公司制度（common/）             │</span></span>
<span class="line"><span>│  所有人都要遵守的通用规则                 │</span></span>
<span class="line"><span>│                                        │</span></span>
<span class="line"><span>│  - 代码风格规范                         │</span></span>
<span class="line"><span>│  - 安全要求                             │</span></span>
<span class="line"><span>│  - 测试要求                             │</span></span>
<span class="line"><span>│  - Git 提交规范                         │</span></span>
<span class="line"><span>│  - 性能要求                             │</span></span>
<span class="line"><span>│  - 开发工作流                            │</span></span>
<span class="line"><span>└────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌────────────────────────────────────────┐</span></span>
<span class="line"><span>│  第二层：部门规章（python/、java/、go/）  │</span></span>
<span class="line"><span>│  每个语言/框架自己的特殊规则              │</span></span>
<span class="line"><span>│                                        │</span></span>
<span class="line"><span>│  Python 部门：                          │</span></span>
<span class="line"><span>│  - 用 type hints                       │</span></span>
<span class="line"><span>│  - 用 pytest                           │</span></span>
<span class="line"><span>│  - 遵循 PEP 8                          │</span></span>
<span class="line"><span>│                                        │</span></span>
<span class="line"><span>│  Java 部门：                            │</span></span>
<span class="line"><span>│  - 用 JUnit 5                          │</span></span>
<span class="line"><span>│  - 遵循 Google Java Style              │</span></span>
<span class="line"><span>│                                        │</span></span>
<span class="line"><span>│  Go 部门：                              │</span></span>
<span class="line"><span>│  - 用 gofmt                            │</span></span>
<span class="line"><span>│  - 错误必须处理，不能忽略                 │</span></span>
<span class="line"><span>│  - 用 table-driven tests               │</span></span>
<span class="line"><span>└────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br></div></div><p><strong>为什么要这样分？</strong></p><ol><li><strong>避免重复</strong> — &quot;代码不超过 800 行&quot;这条规则适用于所有语言，写一次就够了</li><li><strong>方便维护</strong> — 改一个通用规则，所有语言都生效；改一个语言规则，不影响其他语言</li><li><strong>逻辑清晰</strong> — 通用的归通用，特殊的归特殊，不混在一起</li></ol><p>打个比方：公司有&quot;全公司制度&quot;（比如不能迟到早退），也有&quot;部门规章&quot;（比如设计部用 Figma，研发部用 VS Code）。两者都要遵守，但性质不同。</p><hr><h2 id="为什么支持-11-种语言" tabindex="-1">为什么支持 11 种语言？ <a class="header-anchor" href="#为什么支持-11-种语言" aria-label="Permalink to &quot;为什么支持 11 种语言？&quot;">​</a></h2><p>因为<strong>真实项目是多语言的。</strong></p><p>一个典型的全栈项目可能长这样：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>一个现代 Web 应用：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  ├── 前端（TypeScript + React）</span></span>
<span class="line"><span>  ├── 后端 API（Python + FastAPI）</span></span>
<span class="line"><span>  ├── 微服务（Go）</span></span>
<span class="line"><span>  ├── 数据库迁移（SQL）</span></span>
<span class="line"><span>  ├── 基础设施（YAML / HCL）</span></span>
<span class="line"><span>  └── 自动化测试（JavaScript / Python）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>如果 Rules 只支持 TypeScript → Python 代码没有约束</span></span>
<span class="line"><span>如果 Rules 只支持 Python → Go 代码没有约束</span></span>
<span class="line"><span>如果 Rules 只支持后端 → 前端代码没有约束</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p><strong>Rules 系统覆盖了 11 种主流语言，每种语言都有多类规则：</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>语言覆盖矩阵</span></span>
<span class="line"><span>════════════</span></span>
<span class="line"><span></span></span>
<span class="line"><span>            公共  Python  Java  Go  Rust  Swift  Kotlin  C++  C#  PHP  TS  Perl</span></span>
<span class="line"><span>            ────  ──────  ────  ──  ────  ─────  ──────  ───  ──  ───  ──  ────</span></span>
<span class="line"><span>编码风格      ✅     ✅     ✅   ✅   ✅     ✅      ✅    ✅   ✅   ✅   ✅   ✅</span></span>
<span class="line"><span>安全要求      ✅     ✅     ✅   ✅   ✅     ✅      ✅    ✅   ✅   ✅   ✅   ✅</span></span>
<span class="line"><span>测试要求      ✅     ✅     ✅   ✅   ✅     ✅      ✅    ✅   ✅   ✅   ✅   ✅</span></span>
<span class="line"><span>Git 规范     ✅     -      -    -    -      -       -     -    -    -    -    -</span></span>
<span class="line"><span>开发工作流    ✅     -      -    -    -      -       -     -    -    -    -    -</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>这样不管你项目的代码库里有几种语言，Rules 都能覆盖到。</p><hr><h2 id="rules-和-hooks-的关系-立法者与执法者" tabindex="-1">Rules 和 Hooks 的关系：立法者与执法者 <a class="header-anchor" href="#rules-和-hooks-的关系-立法者与执法者" aria-label="Permalink to &quot;Rules 和 Hooks 的关系：立法者与执法者&quot;">​</a></h2><p>这是理解 Rules 系统最关键的一点。</p><p><strong>Rules 是&quot;法律条文&quot;，Hooks 是&quot;执法者&quot;。</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>类比：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Rules = 国家法律</span></span>
<span class="line"><span>  &quot;高速公路限速 120 km/h&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Hooks = 路上的测速摄像头 + 交警</span></span>
<span class="line"><span>  &quot;你超速了，摄像头拍到，交警拦下&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>光有 Rules 没有 Hooks：</p><ul><li>AI 看了 Rules，说&quot;好的&quot;</li><li>写代码的时候忘了</li><li>代码审查时才发现违规</li><li>已经晚了</li></ul><p>光有 Hooks 没有 Rules：</p><ul><li>Hook 知道要拦截，但不知道&quot;什么算违规&quot;</li><li>没有判断标准</li><li>执法没有依据</li></ul><p><strong>两者配合才是完整的&quot;治理体系&quot;：</strong></p>`,35)),(a(),e(c,null,{default:n(()=>[r(l,{id:"mermaid-134",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20RULES%5B%22%F0%9F%93%8B%20Rules%EF%BC%88%E6%B3%95%E5%BE%8B%EF%BC%89%5Cn%E5%AE%9A%E4%B9%89%E6%A0%87%E5%87%86%5Cn%E4%BE%8B%EF%BC%9A%E6%96%87%E4%BB%B6%E4%B8%8D%E8%B6%85%E8%BF%87%20800%20%E8%A1%8C%22%5D%0A%20%20%20%20HOOKS%5B%22%F0%9F%AA%9D%20Hooks%EF%BC%88%E6%89%A7%E6%B3%95%E8%80%85%EF%BC%89%5Cn%E5%AE%9E%E6%97%B6%E6%A3%80%E6%9F%A5%5Cn%E5%86%99%E6%96%87%E4%BB%B6%E6%97%B6%E6%A3%80%E6%9F%A5%E8%A1%8C%E6%95%B0%22%5D%0A%20%20%20%20BLOCK%5B%22%F0%9F%9A%AB%20%E8%BF%9D%E8%A7%84%E6%8B%A6%E6%88%AA%5Cn%E8%B6%85%E8%BF%87%E5%B0%B1%E9%98%BB%E6%AD%A2%E5%86%99%E5%85%A5%5Cn%E6%8F%90%E7%A4%BA%EF%BC%9A%E6%8B%86%E5%88%86%E6%96%87%E4%BB%B6%22%5D%0A%0A%20%20%20%20RULES%20--%3E%7C%22%E5%91%8A%E8%AF%89%20Hooks%20%E4%BB%80%E4%B9%88%E7%AE%97%E8%BF%9D%E8%A7%84%22%7C%20HOOKS%0A%20%20%20%20HOOKS%20--%3E%7C%22%E5%8F%91%E7%8E%B0%E8%BF%9D%E8%A7%84%E6%97%B6%22%7C%20BLOCK%0A%0A%20%20%20%20style%20RULES%20fill%3A%2342a5f5%2Ccolor%3A%23fff%0A%20%20%20%20style%20HOOKS%20fill%3A%23ff9800%2Ccolor%3A%23fff%0A%20%20%20%20style%20BLOCK%20fill%3A%23ef5350%2Ccolor%3A%23fff%0A"})]),fallback:n(()=>[...s[0]||(s[0]=[i(" Loading... ",-1)])]),_:1})),s[3]||(s[3]=p(`<p>再看几个 Rules + Hooks 配合的例子：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Rules 说                       Hooks 做</span></span>
<span class="line"><span>════════                       ════════</span></span>
<span class="line"><span>&quot;不能有 console.log&quot;       →   写入前扫描，发现就阻止</span></span>
<span class="line"><span>&quot;必须有测试文件&quot;            →   创建源文件时检查对应测试文件</span></span>
<span class="line"><span>&quot;不能提交密钥&quot;             →   git commit 前扫描，有密钥就拒绝</span></span>
<span class="line"><span>&quot;函数不超过 50 行&quot;         →   写函数时检查行数</span></span>
<span class="line"><span>&quot;import 不能用相对路径&quot;     →   写 import 时检查格式</span></span>
<span class="line"><span>&quot;单引号，不用双引号&quot;        →   写入时自动修正引号风格</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p><strong>没有 Hooks 的 Rules 是&quot;纸老虎&quot;——好看但没用。没有 Rules 的 Hooks 是&quot;无头苍蝇&quot;——有力气没方向。两者缺一不可。</strong></p><hr><h2 id="rules-文件长什么样" tabindex="-1">Rules 文件长什么样？ <a class="header-anchor" href="#rules-文件长什么样" aria-label="Permalink to &quot;Rules 文件长什么样？&quot;">​</a></h2><p>你可能好奇 Rules 文件里面写了什么。<strong>就是大白话。</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>rules/common/coding-style.md（示意）</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 编码风格规范</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 变量命名</span></span>
<span class="line"><span>- 使用有意义的变量名，禁止 a、b、tmp、data</span></span>
<span class="line"><span>- 布尔值用 is/has/can 前缀：isActive、hasError、canEdit</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 函数长度</span></span>
<span class="line"><span>- 单个函数不超过 50 行</span></span>
<span class="line"><span>- 超过 30 行就要考虑拆分</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 注释</span></span>
<span class="line"><span>- 公共 API 必须有注释</span></span>
<span class="line"><span>- 复杂逻辑必须有行内注释</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 文件大小</span></span>
<span class="line"><span>- 单个文件不超过 800 行</span></span>
<span class="line"><span>- 超过 500 行就要考虑拆分</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br></div></div><p>没有 YAML，没有 JSON，没有复杂配置。<strong>就是用大白话告诉 AI &quot;你应该怎么做&quot;。</strong> 跟 Skills 一样，用 Markdown 写——人和 AI 都能读懂。</p><hr><h2 id="rules-vs-skills-vs-commands-三者的完整关系" tabindex="-1">Rules vs Skills vs Commands：三者的完整关系 <a class="header-anchor" href="#rules-vs-skills-vs-commands-三者的完整关系" aria-label="Permalink to &quot;Rules vs Skills vs Commands：三者的完整关系&quot;">​</a></h2><p>学到这里，三个核心概念都讲完了。来做最后一个对比：</p>`,11)),(a(),e(c,null,{default:n(()=>[r(l,{id:"mermaid-160",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20USER%5B%22%F0%9F%91%A4%20%E7%94%A8%E6%88%B7%22%5D%20--%3E%20CMD%5B%22%F0%9F%93%8B%20Commands%5Cn%E4%BD%A0%E8%AF%B4%E7%9A%84%E8%AF%9D%5Cn%2Fplan%20%2Ftdd%20%2Fverify%22%5D%0A%20%20%20%20CMD%20--%3E%20SKILL%5B%22%F0%9F%93%96%20Skills%5CnAI%20%E7%9A%84%E6%96%B9%E6%B3%95%E8%AE%BA%5CnTDD%20%E6%B5%81%E7%A8%8B%E3%80%81%E9%AA%8C%E8%AF%81%E5%BE%AA%E7%8E%AF%22%5D%0A%20%20%20%20SKILL%20--%3E%20RULE%5B%22%F0%9F%93%9C%20Rules%5Cn%E6%89%80%E6%9C%89%E4%BA%BA%E9%81%B5%E5%AE%88%E7%9A%84%E6%B3%95%E5%BE%8B%5Cn%E7%BC%96%E7%A0%81%E9%A3%8E%E6%A0%BC%E3%80%81%E5%AE%89%E5%85%A8%E3%80%81%E6%B5%8B%E8%AF%95%22%5D%0A%20%20%20%20RULE%20--%3E%20HOOK%5B%22%F0%9F%AA%9D%20Hooks%5Cn%E6%89%A7%E6%B3%95%E8%80%85%5Cn%E5%AE%9E%E6%97%B6%E6%A3%80%E6%9F%A5%E3%80%81%E6%8B%A6%E6%88%AA%E8%BF%9D%E8%A7%84%22%5D%0A%0A%20%20%20%20style%20USER%20fill%3A%2342a5f5%2Ccolor%3A%23fff%0A%20%20%20%20style%20CMD%20fill%3A%23ff9800%2Ccolor%3A%23fff%0A%20%20%20%20style%20SKILL%20fill%3A%2366bb6a%2Ccolor%3A%23fff%0A%20%20%20%20style%20RULE%20fill%3A%23ab47bc%2Ccolor%3A%23fff%0A%20%20%20%20style%20HOOK%20fill%3A%23ef5350%2Ccolor%3A%23fff%0A"})]),fallback:n(()=>[...s[1]||(s[1]=[i(" Loading... ",-1)])]),_:1})),s[4]||(s[4]=p(`<p><strong>一个完整的工作场景：</strong></p><blockquote><p>你输入 <code>/tdd 写一个排序函数</code> ← Command（你说的话） AI 加载 TDD 工作流 Skill ← Skill（方法论：先写测试再写代码） AI 写代码时遵守 Rules ← Rules（约束：camelCase 命名、不超过 50 行） Hooks 实时检查 ← Hook（执法：写入前检查行数和风格）</p></blockquote><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>四者配合：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Commands = 你点的菜（&quot;我要 TDD&quot;）</span></span>
<span class="line"><span>  Skills   = 厨师的菜谱（&quot;TDD 怎么做&quot;）</span></span>
<span class="line"><span>  Rules    = 食品安全法规（&quot;必须用新鲜食材&quot;）</span></span>
<span class="line"><span>  Hooks    = 卫生检查员（&quot;过期食材？不让用&quot;）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><hr><h2 id="我需要手动配置吗" tabindex="-1">我需要手动配置吗？ <a class="header-anchor" href="#我需要手动配置吗" aria-label="Permalink to &quot;我需要手动配置吗？&quot;">​</a></h2><p><strong>99% 的情况下，不需要。</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>需要配置的情况                不需要配置的情况</span></span>
<span class="line"><span>══════════════                ════════════════</span></span>
<span class="line"><span>你公司有特殊编码规范           你用的是主流语言和框架</span></span>
<span class="line"><span>你想加自定义规则              默认规则已经很合理</span></span>
<span class="line"><span>你想覆盖某些默认规则          你只是个人开发</span></span>
<span class="line"><span>你想调整规则的严格程度        你对默认标准满意</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>默认的 Rules 已经覆盖了主流语言的最佳实践。你打开就能用，不需要任何配置。</p><p>如果你确实想定制——直接编辑对应的 <code>.md</code> 文件就行。就像改一份 Word 文档一样简单。</p><hr><h2 id="好处和代价" tabindex="-1">好处和代价 <a class="header-anchor" href="#好处和代价" aria-label="Permalink to &quot;好处和代价&quot;">​</a></h2><p><strong>好处：</strong></p><ul><li>🎯 跨项目风格一致——不管做什么项目，AI 输出的风格统一</li><li>📝 Markdown 格式——人和 AI 都能看懂、编辑</li><li>🏗️ 分层设计——通用规则不重复，语言规则不冲突</li><li>🔗 与 Hooks 配合——有规则有执法，不是纸老虎</li><li>🌍 11 种语言覆盖——真实项目能用到</li></ul><p><strong>代价：</strong></p><ul><li>📜 规则太多可能让 AI 过于保守（不过可以调整严格度）</li><li>⚖️ 不同规则之间可能有优先级冲突</li><li>🔄 规则更新需要重新加载</li></ul><hr><h2 id="对你自己的项目的启发" tabindex="-1">对你自己的项目的启发 <a class="header-anchor" href="#对你自己的项目的启发" aria-label="Permalink to &quot;对你自己的项目的启发&quot;">​</a></h2><ol><li><strong>分层设计是好习惯</strong> — 通用的规则写一层，特殊的规则写一层。不要把所有东西都塞在一起</li><li><strong>规则要配执法</strong> — 光有文档没有检查机制，规则就是摆设。要么用 Hooks，要么用 CI，总之要有自动化的执行手段</li><li><strong>Markdown 适合写&quot;规范&quot;</strong> — 如果你有团队编码规范，不要放在 Wiki 里（没人看），放在 AI 能读取的地方，让 TA 自动执行</li><li><strong>多语言支持是刚需</strong> — 如果你的团队/产品涉及多种语言，规则体系必须能覆盖所有语言</li></ol><blockquote><p>💡 <strong>下一步</strong>：你可以先不管 Rules，用默认配置就好。等你熟悉了整个系统之后，再来看看 <code>rules/</code> 目录，了解有哪些规矩在默默生效。</p></blockquote>`,19))])}const B=o(b,[["render",m]]);export{C as __pageData,B as default};
